var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"좋아. 그럼 이제부터 작전의 개요를 설명할게.","JPN":"さあ、これから作戦の概要を説明するね。","ENG":"Anyway. Let me explain how this is going to work.","TWN":"好。那麼我現在來說明作戰計畫的概要。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"브레인 데스 작전은 공략이 어려운 적의 하드웨어 대신, 두뇌 역할을 하는 통제코어를 파괴해서 테라사이드 시스템 전체를 정지시키는 거야.","JPN":"ブレイン・デス作戦は、攻略が困難な敵のハードウェアの代わりに、\\n頭脳役の統制コアを破壊してテラサイドシステム全体を止めるものなの。","ENG":"Instead of striking the hard outer shell of the enemy, we're going to destroy the main control core, the \\"brain,\\" to bring the entire System Terraside to a halt.","TWN":"腦死作戰不是針對敵人難以攻略的硬體，而是破壞擔任大腦角色的控制核心，使特拉賽德系統整體停擺。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"말 그대로 뇌사상태로 만드는 거지.","JPN":"いわゆる脳死状態にするのよ。","ENG":"Hence the name, Brain Death.","TWN":"就像作戰名一樣，使敵人成為腦死狀態。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 불멸체 코어 아니었어?","JPN":"それが不滅体コアなんじゃないの？","ENG":"Isn't it the Immortal System Core that you're talking about?","TWN":"那不就是不滅者核心嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그것만 부수면 테라사이드 시스템이 붕괴한다고......","JPN":"それさえ壊せば、テラサイドシステムが崩壊するって……","ENG":"I heard that if we destroy that thing, the entire System Terraside would collapse.","TWN":"妳是說只要破壞了那個，特拉賽德系統就會崩壞……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"맞아. 하지만 불멸체 코어는 뉴 오하이오의 중추부에서 리플레이서 최고 간부들에게 보호받고 있다고.","JPN":"そうよ、でも不滅体コアはニューオハイオの中枢でリプレイサーの最高幹部らに守られているのよ。","ENG":"Correct. But that thing is guarded by the finest Replacer officers deep within the walls of the New Ohio.","TWN":"沒錯。但是不滅者核心在新俄亥俄的中樞，由克隆集團最高幹部保護著。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"애초에 그걸 부술 수 있다면 우리가 여기서 만날 이유도 없었겠지.","JPN":"それが破壊できてたら、私たちがここで会う理由もなかったでしょうね。","ENG":"If we could destroy it, we wouldn't have had to come all the way here.","TWN":"要是我從一開始就可以破壞掉它，我們就不會在這裡見面了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼?","JPN":"つまり？","ENG":"What are you saying?","TWN":"那現在？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내가 알아낸 바에 따르면 테라사이드 시스템은 아무나 동작시킬 수 있는 게 아니야.","JPN":"私が調べた結果、テラサイドシステムは誰にでも動かせるものではない。","ENG":"According to my findings, System Terraside cannot be operated by just anybody.","TWN":"據我所知，特拉賽德系統不是誰都可以操作的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"애초에 불멸체 코어든 테라사이드 시스템이든, 기본 설계는 모두 로스트 쉽에 남겨진 구 관리국의 정보를 토대로 만들어 진 거야.","JPN":"そもそもの不滅体コアも、テラサイドシステムも、\\n基本設計はすべてロストシップに残された旧管理局の情報をベースに作られているのよ。","ENG":"Both the Immortal System Core and System Terraside were built based on the Old Administration's technology discovered in the Lost Ships.","TWN":"不管是不滅者核心，還是特拉賽德系統，當初都是以失落艦船上遺留的舊管理局資訊為基礎製造的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당연히 해당 시스템에 명령을 내리려면 구 관리국의 시스템 통제용 어셈블리 코드를 만들어 낼 수 있어야 한다고.","JPN":"当然、そのシステムに命令するためには、\\n旧管理局のシステム統制用のアセンブリコードを生成しなければならないの。","ENG":"And they need the Old Administration's system control assembly code to give orders to the system.","TWN":"當然，要對那個系統下指令，就必須生成舊管理局系統控制用的彙編代碼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"다시 말해, 통제코어가 없으면 테라사이드 시스템은 아무도 명령을 내릴 수 없는 멋진 고철더미에 불과하다는 뜻이지.","JPN":"言い換えれば、統制コアのないテラサイドシステムなんて、\\n誰の命令も受け付けない鉄の塊に過ぎないってことよ。","ENG":"That is, without the control core, System Terraside is nothing but a fancy-looking pile of junk that doesn't follow orders from anyone.","TWN":"換句話說，如果沒有控制核心，特拉賽德系統就只是一堆無法下達指令的廢鐵而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그래? 그럼 당장 부수러 가자고!","JPN":"そうか、だったら今すぐぶち壊しに行こうぜ！","ENG":"Yeah? Then let's start smashing things up!","TWN":"是嗎？那我們現在就去破壞掉它！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"넌 제발 입 좀 다물어. 분위기 파악 좀 하고.","JPN":"あんたはちょっと黙っててよ。お願いだから少しは空気読んで。","ENG":"You just keep your mouth shut. Have some sense for once, for crying out loud.","TWN":"拜託妳閉嘴，看看氣氛好不好。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야? 왜 날 바라보는 건데?","JPN":"何よ、何で見つめるのよ？","ENG":"Hmm? Why are you looking at me?","TWN":"怎麼了？你們盯著我幹嘛？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"통제코어는 그 특성상 테라사이드 시스템의 명령권자 역할을 겸임하고 있어.","JPN":"統制コアはその特性上、テラサイドシステムの命令権者の役割も兼ねているの。","ENG":"The control core, in its nature, also acts as the highest authority in System Terraside.","TWN":"控制核心在性質上，還兼任特拉賽德系統的命令權者。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};